interface PageProps {
  params: Promise<{
    service: string;
    industry: string;
    location: string;
  }>;
}

export async function generateStaticParams() {
  const params = [];
  // Limit the generated static params for the initial build to avoid long build times
  // In production, you would generate all permutations or use incremental static regeneration
  for (const s of SERVICES_LIST.slice(0, 3)) {
    for (const i of INDUSTRIES_LIST.slice(0, 3)) {
      for (const l of LOCATIONS_LIST.slice(0, 3)) {
        params.push({ service: s.slug, industry: i.slug, location: l.slug });
      }
    }
  }
  return params;
}

export async function generateMetadata({ params }: PageProps) {
  const resolvedParams = await params;
  const s = SERVICES_LIST.find(x => x.slug === resolvedParams.service)?.name || resolvedParams.service;
  const i = INDUSTRIES_LIST.find(x => x.slug === resolvedParams.industry)?.name || resolvedParams.industry;
  const l = LOCATIONS_LIST.find(x => x.slug === resolvedParams.location)?.name || resolvedParams.location;

  return seo({
    title: `Custom ${s} for ${i} in ${l} | Agara Sofvix`,
    description: `Scale your ${i} business in ${l} with our specialized ${s} solutions. AI-powered, scalable, and built for local growth.`,
    path: `/${resolvedParams.service}/${resolvedParams.industry}/${resolvedParams.location}`,
    keywords: [resolvedParams.service, resolvedParams.industry, resolvedParams.location, "custom software", "enterprise solutions"]
  });
}

